function createNewGame(name){var games=getAllGames();var newGame={id:Date.now().toString(),name:name||'Game '+(games.length+1),saves:[],created:Date.now()};games.push(newGame);saveAllGames(games);currentGameId=newGame.id;creativeMode=(newGame.name==='CapyBopyCIG');startCutscene(function(){menuActive=false;init();restartTimer();});}

// === CAPY 3 ===
var capy3Running=false,capy3Rocks=[],capy3Raindrops=[];
function placeCapy3Rocks(){capy3Rocks=[];for(var i=0;i<25;i++){var r;do{r={x:Math.floor(Math.random()*COLS),y:Math.floor(Math.random()*ROWS)};}while(snake.some(function(s){return s.x===r.x&&s.y===r.y;})||capy3Rocks.some(function(rk){return rk.x===r.x&&rk.y===r.y;})||(Math.abs(r.x-snake[0].x)+Math.abs(r.y-snake[0].y)<3));capy3Rocks.push(r);}}

function enterCapy3(){if(!mainGameState)mainGameState=getGameState();currentScreen='capy3';clearInterval(tickInterval);if(capy4StormTimer){clearTimeout(capy4StormTimer);capy4StormTimer=null;}var mid=Math.floor(ROWS/2);snake=[{x:5,y:mid}];for(var i=1;i<=goldCount+1;i++)snake.push({x:5-i,y:mid});placeCapy3Rocks();capy3Raindrops=[];var startX=5;while(snake.some(function(s){return capy3Rocks.some(function(r){return r.x===s.x&&r.y===s.y;});})){startX++;snake=[{x:startX,y:mid}];for(var j=1;j<=goldCount+1;j++)snake.push({x:startX-j,y:mid});}dir={x:1,y:0};nextDir={x:1,y:0};bullets=[];shooting=false;capy3Running=false;tickInterval=setInterval(stepCapy3,parseInt(speedEl.value));drawCapy3();msgEl.textContent='Capy 3 — Arrow keys to move, ESC to return';}

function stepCapy3(){if(!capy3Running||currentScreen!=='capy3')return;dir={x:nextDir.x,y:nextDir.y};var head={x:snake[0].x+dir.x,y:snake[0].y+dir.y};if(head.x<0||head.x>=COLS||head.y<0||head.y>=ROWS)return die();if(snake.some(function(s){return s.x===head.x&&s.y===head.y;}))return die();if(capy3Rocks.some(function(r){return r.x===head.x&&r.y===head.y;}))return die();snake.unshift(head);snake.pop();if(Math.random()<0.3){var type=Math.random()<1/3?'pink':'blue';capy3Raindrops.push({x:Math.floor(Math.random()*COLS),y:0,type:type});}for(var i=capy3Raindrops.length-1;i>=0;i--){var drop=capy3Raindrops[i];var ny=drop.y+1;if(ny>=ROWS||capy3Rocks.some(function(r){return r.x===drop.x&&r.y===ny;})){capy3Raindrops.splice(i,1);continue;}drop.y=ny;if(snake.some(function(s){return s.x===drop.x&&s.y===drop.y;})){capy3Raindrops.splice(i,1);if(drop.type==='pink'){goldCount++;score=goldCount;scoreEl.textContent=score;if(score>best){best=score;bestEl.textContent=best;}snake.push({x:snake[snake.length-1].x,y:snake[snake.length-1].y});}else{if(Math.random()<0.5){if(goldCount>0){goldCount--;score=goldCount;scoreEl.textContent=score;}}else{if(snake.length-1-goldCount>0)snake.pop();}if(snake.length<=1&&goldCount<=0){die();return;}}}}drawCapy3();}

function drawCapy3(){ctx.fillStyle='#0d0d1f';ctx.fillRect(0,0,canvas.width,canvas.height);ctx.strokeStyle='#1a1a3e';ctx.lineWidth=0.5;for(var i=0;i<=COLS;i++){ctx.beginPath();ctx.moveTo(i*GRID,0);ctx.lineTo(i*GRID,canvas.height);ctx.stroke();}for(var i2=0;i2<=ROWS;i2++){ctx.beginPath();ctx.moveTo(0,i2*GRID);ctx.lineTo(canvas.width,i2*GRID);ctx.stroke();}capy3Rocks.forEach(function(r){var rx=r.x*GRID,ry=r.y*GRID;ctx.fillStyle='#4a4a5a';ctx.fillRect(rx+1,ry+1,GRID-2,GRID-2);ctx.fillStyle='#5a5a6a';ctx.fillRect(rx+3,ry+3,6,5);ctx.fillRect(rx+11,ry+10,5,4);ctx.fillStyle='#3a3a4a';ctx.fillRect(rx+10,ry+3,4,3);ctx.fillRect(rx+3,ry+11,5,3);});capy3Raindrops.forEach(function(d){ctx.fillStyle=d.type==='pink'?'rgba(255,50,150,0.8)':'rgba(100,180,255,0.7)';ctx.shadowColor=d.type==='pink'?'#ff3296':'#64b4ff';ctx.shadowBlur=4;ctx.fillRect(d.x*GRID+4,d.y*GRID+2,GRID-8,GRID-4);ctx.shadowBlur=0;});ctx.strokeStyle='rgba(100,160,255,0.15)';ctx.lineWidth=1;for(var r2=0;r2<30;r2++){var rx2=Math.random()*canvas.width,ry2=Math.random()*canvas.height;ctx.beginPath();ctx.moveTo(rx2,ry2);ctx.lineTo(rx2-1,ry2+8);ctx.stroke();}snake.forEach(function(seg,i){var sx=seg.x*GRID,sy=seg.y*GRID;if(i===0){var cx=sx+GRID/2,cy=sy+GRID/2;ctx.fillStyle='#3b2314';ctx.beginPath();ctx.arc(cx,cy-2,9,Math.PI,0);ctx.fill();ctx.fillStyle='#f5cba7';ctx.beginPath();ctx.arc(cx,cy,8,0,Math.PI*2);ctx.fill();ctx.fillStyle='#3b2314';ctx.beginPath();ctx.ellipse(cx,cy-6,8,4,0,0,Math.PI);ctx.fill();ctx.fillStyle='#fff';ctx.beginPath();ctx.arc(cx-3,cy-1,2.2,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.arc(cx+3,cy-1,2.2,0,Math.PI*2);ctx.fill();ctx.fillStyle='#2c3e50';ctx.beginPath();ctx.arc(cx-3,cy-1,1.2,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.arc(cx+3,cy-1,1.2,0,Math.PI*2);ctx.fill();ctx.strokeStyle='#c0392b';ctx.lineWidth=1;ctx.beginPath();ctx.arc(cx,cy+2,3,0.1*Math.PI,0.9*Math.PI);ctx.stroke();}else{var isG=i<=goldCount;var cx2=sx+GRID/2,cy2=sy+GRID/2;ctx.fillStyle=isG?'#ffd700':'#8B6914';ctx.beginPath();ctx.arc(cx2,cy2,8,0,Math.PI*2);ctx.fill();ctx.fillStyle=isG?'#daa520':'#6B4F10';ctx.beginPath();ctx.arc(cx2-5,cy2-7,3,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.arc(cx2+5,cy2-7,3,0,Math.PI*2);ctx.fill();ctx.fillStyle='#111';ctx.beginPath();ctx.arc(cx2-3,cy2-2,1.5,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.arc(cx2+3,cy2-2,1.5,0,Math.PI*2);ctx.fill();ctx.fillStyle=isG?'#b8860b':'#5a3e1b';ctx.beginPath();ctx.ellipse(cx2,cy2+3,3,2,0,0,Math.PI*2);ctx.fill();}});ctx.fillStyle='#6496ff';ctx.shadowColor='#6496ff';ctx.shadowBlur=15;ctx.font='bold 42px Segoe UI';ctx.textAlign='center';ctx.fillText('Capy 3',canvas.width/2,36);ctx.shadowBlur=0;ctx.fillStyle='#666';ctx.font='14px Segoe UI';ctx.fillText('Press ESC to return',canvas.width/2,canvas.height-15);}

// === CAPY 4 ===
var capy4Running=false,capy4Frogs=[],capy4Storms=[],capy4StormTimer=null;

function scheduleCapy4Storm(){var delay=2000+Math.random()*3000;capy4StormTimer=setTimeout(function(){if(currentScreen!=='capy4'||gameOver)return;var sx,att=0;do{sx=Math.floor(Math.random()*(COLS-1));att++;}while(att<50&&snake.some(function(s){for(var dx=0;dx<2;dx++)for(var dy=0;dy<=6;dy++)if(s.x===sx+dx&&s.y===dy)return true;return false;}));var roll=Math.random(),type;if(roll<0.3)type='deadly';else if(roll<0.3+0.7*0.2)type='capy3';else type='capy5';capy4Storms.push({x:sx,y:0,type:type});setTimeout(function(){capy4Storms=capy4Storms.filter(function(s){return s.x!==sx;});if(currentScreen==='capy4'&&!gameOver){drawCapy4();scheduleCapy4Storm();}},3000);drawCapy4();},delay);}

function checkCapy4Storms(){var head=snake[0];for(var i=capy4Storms.length-1;i>=0;i--){var s=capy4Storms[i];for(var dx=0;dx<2;dx++)for(var dy=1;dy<=6;dy++){if(head.x===s.x+dx&&head.y===s.y+dy){if(s.type==='deadly')return die();if(s.type==='capy3'){if(capy4StormTimer)clearTimeout(capy4StormTimer);enterCapy3();return;}if(capy4StormTimer)clearTimeout(capy4StormTimer);enterCapy5();return;}}}}

function drawCapy4Storm(s){var cx1=s.x*GRID+GRID/2,cx2=(s.x+1)*GRID+GRID/2,cy=s.y*GRID+GRID/2-2;ctx.fillStyle='#555';ctx.beginPath();ctx.arc(cx1,cy,8,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.arc(cx2,cy,8,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.arc((cx1+cx2)/2,cy-4,7,0,Math.PI*2);ctx.fill();if(s.type==='capy3'||s.type==='capy5'){var rx=(cx1+cx2)/2,ry=cy-6;var colors=['#ff0000','#ff8800','#ffff00','#00ff00','#0088ff','#8800ff'];colors.forEach(function(c,ci){ctx.strokeStyle=c;ctx.lineWidth=0.8;ctx.beginPath();ctx.arc(rx,ry,4+ci,Math.PI,0);ctx.stroke();});}ctx.strokeStyle=s.type==='deadly'?'rgba(255,70,70,0.5)':'rgba(100,180,255,0.5)';ctx.lineWidth=1;for(var dx=0;dx<2;dx++)for(var dy=1;dy<=6;dy++){var rx2=(s.x+dx)*GRID,ry2=(s.y+dy)*GRID;if(ry2<canvas.height)for(var r=0;r<3;r++){var ox=rx2+Math.random()*GRID,oy=ry2+Math.random()*GRID;ctx.beginPath();ctx.moveTo(ox,oy);ctx.lineTo(ox-1,oy+5);ctx.stroke();}}ctx.fillStyle=s.type==='deadly'?'rgba(255,50,50,0.06)':'rgba(100,255,200,0.06)';for(var dx2=0;dx2<2;dx2++)for(var dy2=0;dy2<=6;dy2++){var tx=s.x+dx2,ty=s.y+dy2;if(tx<COLS&&ty<ROWS)ctx.fillRect(tx*GRID,ty*GRID,GRID,GRID);}}

function placeFrogs(){capy4Frogs=[];for(var i=0;i<2;i++){var f;do{f={x:Math.floor(Math.random()*COLS),y:Math.floor(Math.random()*ROWS),jumpCooldown:0};}while(snake.some(function(s){return Math.abs(s.x-f.x)<=1&&Math.abs(s.y-f.y)<=1;})||capy4Frogs.some(function(fr){return fr.x===f.x&&fr.y===f.y;}));capy4Frogs.push(f);}}

function moveFrogs(){capy4Frogs.forEach(function(f){f.jumpCooldown--;if(f.jumpCooldown>0)return;var jumpDist=2+Math.floor(Math.random()*3);var d=DIRS[Math.floor(Math.random()*4)];var nx=f.x+d.x*jumpDist,ny=f.y+d.y*jumpDist;f.x=Math.max(0,Math.min(COLS-1,nx));f.y=Math.max(0,Math.min(ROWS-1,ny));f.jumpCooldown=3+Math.floor(Math.random()*3);});}

function checkFrogHits(){capy4Frogs.forEach(function(f){for(var si=0;si<snake.length;si++){var s=snake[si];if(Math.abs(s.x-f.x)<=1&&Math.abs(s.y-f.y)<=1){var bx2=snake[0].x-dir.x*2,by2=snake[0].y-dir.y*2;snake[0].x=Math.max(0,Math.min(COLS-1,bx2));snake[0].y=Math.max(0,Math.min(ROWS-1,by2));var nonGold=snake.length-1-goldCount;if(nonGold>=2){snake.pop();snake.pop();}else if(nonGold===1){snake.pop();if(goldCount>0){goldCount--;score=goldCount;scoreEl.textContent=score;}}else{if(goldCount>0){goldCount--;score=goldCount;scoreEl.textContent=score;}}if(snake.length<=1&&goldCount<=0){die();return;}break;}}});}

function drawFrog(fx,fy){var cx=fx*GRID+GRID/2,cy=fy*GRID+GRID/2;ctx.fillStyle='#27ae60';ctx.beginPath();ctx.arc(cx,cy,7,0,Math.PI*2);ctx.fill();ctx.fillStyle='#fff';ctx.beginPath();ctx.arc(cx-4,cy-5,3.5,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.arc(cx+4,cy-5,3.5,0,Math.PI*2);ctx.fill();ctx.fillStyle='#111';ctx.beginPath();ctx.arc(cx-4,cy-5,1.5,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.arc(cx+4,cy-5,1.5,0,Math.PI*2);ctx.fill();ctx.strokeStyle='#1a7a3a';ctx.lineWidth=1;ctx.beginPath();ctx.arc(cx,cy+2,4,0.1*Math.PI,0.9*Math.PI);ctx.stroke();ctx.strokeStyle='rgba(255,70,70,0.2)';ctx.lineWidth=1;ctx.strokeRect((fx-1)*GRID,(fy-1)*GRID,GRID*3,GRID*3);}

function enterCapy4(){currentScreen='capy4';clearInterval(tickInterval);var mid=Math.floor(ROWS/2);snake=[{x:5,y:mid}];for(var i=1;i<=goldCount+1;i++)snake.push({x:5-i,y:mid});dir={x:1,y:0};nextDir={x:1,y:0};bullets=[];shooting=false;placeFrogs();capy4Storms=[];if(capy4StormTimer)clearTimeout(capy4StormTimer);scheduleCapy4Storm();capy4Running=false;tickInterval=setInterval(stepCapy4,parseInt(speedEl.value));drawCapy4();msgEl.textContent='Capy 4 — Arrow keys to move, ESC to return';}

function stepCapy4(){if(!capy4Running||currentScreen!=='capy4')return;dir={x:nextDir.x,y:nextDir.y};var head={x:snake[0].x+dir.x,y:snake[0].y+dir.y};if(head.x<0||head.x>=COLS||head.y<0||head.y>=ROWS)return die();if(snake.some(function(s){return s.x===head.x&&s.y===head.y;}))return die();snake.unshift(head);snake.pop();moveFrogs();checkFrogHits();checkCapy4Storms();drawCapy4();}

function drawCapy4(){ctx.fillStyle='#0a1a0a';ctx.fillRect(0,0,canvas.width,canvas.height);ctx.strokeStyle='#1a2e1a';ctx.lineWidth=0.5;for(var i=0;i<=COLS;i++){ctx.beginPath();ctx.moveTo(i*GRID,0);ctx.lineTo(i*GRID,canvas.height);ctx.stroke();}for(var i2=0;i2<=ROWS;i2++){ctx.beginPath();ctx.moveTo(0,i2*GRID);ctx.lineTo(canvas.width,i2*GRID);ctx.stroke();}capy4Storms.forEach(function(s){drawCapy4Storm(s);});capy4Frogs.forEach(function(f){drawFrog(f.x,f.y);});snake.forEach(function(seg,i){var sx=seg.x*GRID,sy=seg.y*GRID;if(i===0){var cx=sx+GRID/2,cy=sy+GRID/2;ctx.fillStyle='#3b2314';ctx.beginPath();ctx.arc(cx,cy-2,9,Math.PI,0);ctx.fill();ctx.fillStyle='#f5cba7';ctx.beginPath();ctx.arc(cx,cy,8,0,Math.PI*2);ctx.fill();ctx.fillStyle='#3b2314';ctx.beginPath();ctx.ellipse(cx,cy-6,8,4,0,0,Math.PI);ctx.fill();ctx.fillStyle='#fff';ctx.beginPath();ctx.arc(cx-3,cy-1,2.2,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.arc(cx+3,cy-1,2.2,0,Math.PI*2);ctx.fill();ctx.fillStyle='#2c3e50';ctx.beginPath();ctx.arc(cx-3,cy-1,1.2,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.arc(cx+3,cy-1,1.2,0,Math.PI*2);ctx.fill();ctx.strokeStyle='#c0392b';ctx.lineWidth=1;ctx.beginPath();ctx.arc(cx,cy+2,3,0.1*Math.PI,0.9*Math.PI);ctx.stroke();}else{var isG=i<=goldCount;var cx2=sx+GRID/2,cy2=sy+GRID/2;ctx.fillStyle=isG?'#ffd700':'#8B6914';ctx.beginPath();ctx.arc(cx2,cy2,8,0,Math.PI*2);ctx.fill();ctx.fillStyle=isG?'#daa520':'#6B4F10';ctx.beginPath();ctx.arc(cx2-5,cy2-7,3,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.arc(cx2+5,cy2-7,3,0,Math.PI*2);ctx.fill();ctx.fillStyle='#111';ctx.beginPath();ctx.arc(cx2-3,cy2-2,1.5,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.arc(cx2+3,cy2-2,1.5,0,Math.PI*2);ctx.fill();ctx.fillStyle=isG?'#b8860b':'#5a3e1b';ctx.beginPath();ctx.ellipse(cx2,cy2+3,3,2,0,0,Math.PI*2);ctx.fill();}});ctx.fillStyle='#2ecc71';ctx.shadowColor='#2ecc71';ctx.shadowBlur=15;ctx.font='bold 42px Segoe UI';ctx.textAlign='center';ctx.fillText('Capy 4',canvas.width/2,36);ctx.shadowBlur=0;ctx.fillStyle='#666';ctx.font='14px Segoe UI';ctx.fillText('Press ESC to return',canvas.width/2,canvas.height-15);}

// === CAPY 5 ===
var capy5Running=false,capy5Enemies=[],capy5Boss=null,capy5Player=null,capy5MoveQueued=false,capy5HP=5,capy5Portals=[],capy5Victory=false;
var shieldUses=3,shieldActive5=false,shieldRechargeEnd=0,swordUses=5,swordSpinActive=false,swordSpinEnd=0,swordSpinHit=false,swordRechargeEnd=0;

function placeCapy5Enemies(){capy5Enemies=[];for(var i=0;i<5;i++){var e;do{e={x:Math.floor(Math.random()*COLS),y:Math.floor(Math.random()*ROWS)};}while((capy5Player&&Math.abs(capy5Player.x-e.x)+Math.abs(capy5Player.y-e.y)<4)||capy5Enemies.some(function(f){return f.x===e.x&&f.y===e.y;}));capy5Enemies.push({x:e.x,y:e.y,dir:DIRS[Math.floor(Math.random()*4)],type:'raccoon',hp:1});}var bx,by;do{bx=Math.floor(Math.random()*(COLS-1));by=Math.floor(Math.random()*(ROWS-1));}while(capy5Player&&Math.abs(capy5Player.x-bx)+Math.abs(capy5Player.y-by)<5);capy5Boss={x:bx,y:by,dir:DIRS[Math.floor(Math.random()*4)],armor:3};}

function moveCapy5Enemies(){capy5Enemies.forEach(function(e){if(Math.random()>0.78)return;if(Math.random()<0.3)e.dir=DIRS[Math.floor(Math.random()*4)];var nx=e.x+e.dir.x,ny=e.y+e.dir.y;if(nx<0||nx>=COLS||ny<0||ny>=ROWS){e.dir={x:-e.dir.x,y:-e.dir.y};e.x+=e.dir.x;e.y+=e.dir.y;}else{e.x=nx;e.y=ny;}});if(capy5Boss&&Math.random()<0.5){if(Math.random()<0.3)capy5Boss.dir=DIRS[Math.floor(Math.random()*4)];var nx=capy5Boss.x+capy5Boss.dir.x,ny=capy5Boss.y+capy5Boss.dir.y;if(nx<0||nx>=COLS-1||ny<0||ny>=ROWS-1){capy5Boss.dir={x:-capy5Boss.dir.x,y:-capy5Boss.dir.y};capy5Boss.x+=capy5Boss.dir.x;capy5Boss.y+=capy5Boss.dir.y;}else{capy5Boss.x=nx;capy5Boss.y=ny;}}}

function checkCapy5PlayerHits(){if(!capy5Player||shieldActive5)return;var hitR=capy5Enemies.some(function(e){return e.x===capy5Player.x&&e.y===capy5Player.y;});if(hitR){capy5HP-=1;if(capy5HP<=0)return die();}if(capy5Boss){var hitB=capy5Player.x>=capy5Boss.x&&capy5Player.x<=capy5Boss.x+1&&capy5Player.y>=capy5Boss.y&&capy5Player.y<=capy5Boss.y+1;if(hitB){capy5HP-=capy5Boss.armor;if(capy5HP<=0)return die();}}}

function drawCapy5Boss(){if(!capy5Boss)return;var bx=capy5Boss.x*GRID,by=capy5Boss.y*GRID,cx=bx+GRID,cy=by+GRID,w=GRID*2,h=GRID*2;ctx.fillStyle='rgba(0,0,0,0.3)';ctx.fillRect(bx+3,by+3,w,h);var grad=ctx.createLinearGradient(bx,by,bx+w,by+h);grad.addColorStop(0,'#7a7a8a');grad.addColorStop(0.3,'#9a9aaa');grad.addColorStop(0.5,'#b0b0c0');grad.addColorStop(0.7,'#8a8a9a');grad.addColorStop(1,'#606070');ctx.fillStyle=grad;ctx.fillRect(bx+1,by+1,w-2,h-2);ctx.strokeStyle='#c0c0d0';ctx.lineWidth=1.5;ctx.beginPath();ctx.moveTo(bx+1,by+h-1);ctx.lineTo(bx+1,by+1);ctx.lineTo(bx+w-1,by+1);ctx.stroke();ctx.strokeStyle='#404050';ctx.beginPath();ctx.moveTo(bx+w-1,by+1);ctx.lineTo(bx+w-1,by+h-1);ctx.lineTo(bx+1,by+h-1);ctx.stroke();ctx.fillStyle='#888';ctx.beginPath();ctx.arc(cx,cy,12,0,Math.PI*2);ctx.fill();ctx.fillStyle='#333';ctx.beginPath();ctx.ellipse(cx-5,cy-3,5,4,0,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.ellipse(cx+5,cy-3,5,4,0,0,Math.PI*2);ctx.fill();ctx.shadowColor='#ff0000';ctx.shadowBlur=6;ctx.fillStyle='#f00';ctx.beginPath();ctx.arc(cx-5,cy-3,2.5,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.arc(cx+5,cy-3,2.5,0,Math.PI*2);ctx.fill();ctx.shadowBlur=0;ctx.fillStyle='#111';ctx.beginPath();ctx.arc(cx-5,cy-3,1.2,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.arc(cx+5,cy-3,1.2,0,Math.PI*2);ctx.fill();ctx.fillStyle='#666';ctx.beginPath();ctx.arc(cx-10,cy-11,4,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.arc(cx+10,cy-11,4,0,Math.PI*2);ctx.fill();ctx.fillStyle='#222';ctx.beginPath();ctx.arc(cx,cy+5,3,0,Math.PI*2);ctx.fill();ctx.fillStyle='#ff4757';ctx.shadowColor='#ff4757';ctx.shadowBlur=4;ctx.font='bold 12px Segoe UI';ctx.textAlign='center';var diamonds='';for(var d=0;d<capy5Boss.armor;d++)diamonds+='\u2666';ctx.fillText(diamonds,cx,by-3);ctx.shadowBlur=0;}

function enterCapy5(){if(!mainGameState)mainGameState=getGameState();currentScreen='capy5';clearInterval(tickInterval);if(capy4StormTimer){clearTimeout(capy4StormTimer);capy4StormTimer=null;}var mid=Math.floor(ROWS/2);capy5Player={x:5,y:mid,facing:{x:1,y:0}};dir={x:1,y:0};nextDir={x:1,y:0};bullets=[];shooting=false;capy5MoveQueued=false;capy5HP=5;capy5Portals=[];capy5Victory=false;shieldUses=3;shieldActive5=false;shieldRechargeEnd=0;swordUses=5;swordSpinActive=false;swordSpinEnd=0;swordSpinHit=false;swordRechargeEnd=0;placeCapy5Enemies();capy5Running=false;tickInterval=setInterval(stepCapy5,parseInt(speedEl.value));drawCapy5();msgEl.textContent='Capy 5 — Arrow keys to move, ESC to return';}

function stepCapy5(){if(!capy5Running||currentScreen!=='capy5')return;if(shieldUses<=0&&Date.now()>=shieldRechargeEnd)shieldUses=3;if(swordUses<=0&&Date.now()>=swordRechargeEnd)swordUses=5;if(swordSpinActive&&Date.now()>=swordSpinEnd){swordSpinActive=false;swordSpinHit=false;}if(swordSpinActive&&capy5Player&&!swordSpinHit){swordSpinHit=true;for(var i=capy5Enemies.length-1;i>=0;i--){var e=capy5Enemies[i];if(Math.abs(e.x-capy5Player.x)<=1&&Math.abs(e.y-capy5Player.y)<=1){e.hp--;if(e.hp<=0)capy5Enemies.splice(i,1);}}if(capy5Boss&&Math.abs(capy5Boss.x-capy5Player.x)<=2&&Math.abs(capy5Boss.y-capy5Player.y)<=2){capy5Boss.armor--;if(capy5Boss.armor<=0)capy5Boss=null;}}if(!capy5MoveQueued){moveCapy5Enemies();checkCapy5PlayerHits();drawCapy5();return;}capy5MoveQueued=false;dir={x:nextDir.x,y:nextDir.y};capy5Player.facing={x:dir.x,y:dir.y};var nx=capy5Player.x+dir.x*2,ny=capy5Player.y+dir.y*2;capy5Player.x=Math.max(0,Math.min(COLS-1,nx));capy5Player.y=Math.max(0,Math.min(ROWS-1,ny));moveCapy5Enemies();checkCapy5PlayerHits();if(!capy5Victory&&capy5Enemies.length===0&&!capy5Boss){capy5Victory=true;capy5Portals=[{x:5,y:Math.floor(ROWS/2),label:'Capy 6',color:'#ff6b6b',dest:'capy6'},{x:10,y:Math.floor(ROWS/2),label:'Capy 7',color:'#ffd93d',dest:'capy7'},{x:15,y:Math.floor(ROWS/2),label:'Capy 8',color:'#6bcb77',dest:'capy8'}];}if(capy5Victory&&capy5Player){var hitP=capy5Portals.find(function(p){return p.x===capy5Player.x&&p.y===capy5Player.y;});if(hitP){clearInterval(tickInterval);msgEl.textContent=hitP.label+' — Coming Soon!';drawCapy5();return;}}drawCapy5();}

function drawCapy5(){ctx.fillStyle='#0d0a1a';ctx.fillRect(0,0,canvas.width,canvas.height);ctx.strokeStyle='#1a1a30';ctx.lineWidth=0.5;for(var i=0;i<=COLS;i++){ctx.beginPath();ctx.moveTo(i*GRID,0);ctx.lineTo(i*GRID,canvas.height);ctx.stroke();}for(var i2=0;i2<=ROWS;i2++){ctx.beginPath();ctx.moveTo(0,i2*GRID);ctx.lineTo(canvas.width,i2*GRID);ctx.stroke();}ctx.fillStyle='rgba(255,255,255,0.3)';for(var s=0;s<15;s++){var sx2=((s*97+13)%COLS)*GRID+10,sy2=((s*53+7)%ROWS)*GRID+10;ctx.beginPath();ctx.arc(sx2,sy2,1,0,Math.PI*2);ctx.fill();}capy5Portals.forEach(function(p){var px=p.x*GRID,py=p.y*GRID;ctx.shadowColor=p.color;ctx.shadowBlur=10;ctx.fillStyle=p.color;ctx.fillRect(px+2,py+2,GRID-4,GRID-4);ctx.shadowBlur=0;ctx.strokeStyle='#fff';ctx.lineWidth=1.5;ctx.strokeRect(px+2,py+2,GRID-4,GRID-4);ctx.fillStyle='#fff';ctx.font='bold 8px Segoe UI';ctx.textAlign='center';ctx.fillText(p.label,px+GRID/2,py-3);});capy5Enemies.forEach(function(e){drawRaccoon(e.x*GRID+GRID/2,e.y*GRID+GRID/2);});drawCapy5Boss();if(capy5Player){var px2=capy5Player.x*GRID+GRID/2,py2=capy5Player.y*GRID+GRID/2,f=capy5Player.facing;var shX=px2-f.y*10,shY=py2+f.x*10;ctx.fillStyle='#a0a0d0';ctx.beginPath();ctx.ellipse(shX,shY,5,7,0,0,Math.PI*2);ctx.fill();ctx.strokeStyle='#9090c0';ctx.lineWidth=1;ctx.beginPath();ctx.ellipse(shX,shY,5,7,0,0,Math.PI*2);ctx.stroke();ctx.fillStyle='#d470ff';ctx.beginPath();ctx.arc(shX,shY,2,0,Math.PI*2);ctx.fill();var sbX=px2+f.y*8,sbY=py2-f.x*8,stX=sbX+f.x*14,stY=sbY+f.y*14;ctx.strokeStyle='#e0e0f0';ctx.lineWidth=2;ctx.beginPath();ctx.moveTo(sbX,sbY);ctx.lineTo(stX,stY);ctx.stroke();ctx.strokeStyle='#ffd700';ctx.lineWidth=2;ctx.beginPath();ctx.moveTo(sbX-f.y*3,sbY+f.x*3);ctx.lineTo(sbX+f.y*3,sbY-f.x*3);ctx.stroke();ctx.strokeStyle='#8B4513';ctx.lineWidth=2.5;ctx.beginPath();ctx.moveTo(sbX,sbY);ctx.lineTo(sbX-f.x*5,sbY-f.y*5);ctx.stroke();ctx.fillStyle='#9b59b6';ctx.beginPath();ctx.arc(px2,py2,7,0,Math.PI*2);ctx.fill();ctx.fillStyle='#7d3c98';ctx.beginPath();ctx.arc(px2-5,py2-6,2.5,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.arc(px2+5,py2-6,2.5,0,Math.PI*2);ctx.fill();ctx.fillStyle='#fff';ctx.beginPath();ctx.arc(px2-3,py2-2,1.8,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.arc(px2+3,py2-2,1.8,0,Math.PI*2);ctx.fill();ctx.fillStyle='#111';ctx.beginPath();ctx.arc(px2-3,py2-2,0.9,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.arc(px2+3,py2-2,0.9,0,Math.PI*2);ctx.fill();ctx.fillStyle='#6c3483';ctx.beginPath();ctx.ellipse(px2,py2+2,2.5,1.5,0,0,Math.PI*2);ctx.fill();}if(shieldActive5&&capy5Player){ctx.strokeStyle='rgba(100,150,255,0.6)';ctx.shadowColor='#6496ff';ctx.shadowBlur=12;ctx.lineWidth=3;ctx.beginPath();ctx.arc(capy5Player.x*GRID+GRID/2,capy5Player.y*GRID+GRID/2,14,0,Math.PI*2);ctx.stroke();ctx.shadowBlur=0;}if(swordSpinActive&&capy5Player){var px3=capy5Player.x*GRID+GRID/2,py3=capy5Player.y*GRID+GRID/2;ctx.strokeStyle='rgba(255,255,255,0.5)';ctx.lineWidth=2;var angle=(Date.now()%500)/500*Math.PI*2;for(var a=0;a<4;a++){var aa=angle+a*Math.PI/2;ctx.beginPath();ctx.moveTo(px3+Math.cos(aa)*5,py3+Math.sin(aa)*5);ctx.lineTo(px3+Math.cos(aa)*16,py3+Math.sin(aa)*16);ctx.stroke();}}ctx.fillStyle='#d470ff';ctx.shadowColor='#d470ff';ctx.shadowBlur=15;ctx.font='bold 42px Segoe UI';ctx.textAlign='center';ctx.fillText('Capy 5',canvas.width/2,36);ctx.shadowBlur=0;ctx.textAlign='left';ctx.font='12px Segoe UI';ctx.fillStyle=capy5HP>=4?'#2ecc71':capy5HP>=3?'#f1c40f':'#e74c3c';var hearts='';for(var hi=0;hi<capy5HP;hi++)hearts+='\u2665';for(var hj=0;hj<Math.max(0,5-capy5HP);hj++)hearts+='\u2661';ctx.fillText(hearts,8,canvas.height-44);var shDisp=shieldUses>0?shieldUses:(Date.now()<shieldRechargeEnd?'wait':3);ctx.fillStyle=shieldUses>0?'#6496ff':'#555';ctx.fillText('Shield: '+shDisp,8,canvas.height-28);var swDisp=swordUses>0?swordUses:(Date.now()<swordRechargeEnd?'wait':5);ctx.fillStyle=swordUses>0?'#e0e0f0':'#555';ctx.fillText('Sword: '+swDisp,8,canvas.height-12);ctx.textAlign='center';ctx.fillStyle='#666';ctx.font='14px Segoe UI';ctx.fillText('Shift=Shield | Ctrl=Sword | /=Super | ESC=return',canvas.width/2,canvas.height-15);}

// === MENU ===
var menuActive=true,gameSelectActive=false,gameDeleteMode=false,namingActive=false,nameInput='',renamingGameIdx=-1;

function drawMenu(){ctx.fillStyle='#0a0a1a';ctx.fillRect(0,0,canvas.width,canvas.height);ctx.fillStyle='#00ff88';ctx.shadowColor='#00ff88';ctx.shadowBlur=20;ctx.font='bold 48px Segoe UI';ctx.textAlign='center';ctx.fillText('CrawlingCapys',canvas.width/2,100);ctx.shadowBlur=0;var cx=canvas.width/2;ctx.fillStyle='#8B6914';ctx.beginPath();ctx.arc(cx,160,20,0,Math.PI*2);ctx.fill();ctx.fillStyle='#6B4F10';ctx.beginPath();ctx.arc(cx-12,145,6,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.arc(cx+12,145,6,0,Math.PI*2);ctx.fill();ctx.fillStyle='#111';ctx.beginPath();ctx.arc(cx-6,157,3,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.arc(cx+6,157,3,0,Math.PI*2);ctx.fill();ctx.fillStyle='#5a3e1b';ctx.beginPath();ctx.ellipse(cx,167,6,4,0,0,Math.PI*2);ctx.fill();var games=getAllGames();ctx.font='bold 22px Segoe UI';ctx.fillStyle='#00ff88';ctx.fillText('[1] New Game',cx,240);if(games.length>0){ctx.fillStyle='#ffd700';ctx.fillText('[2] Play Old Game',cx,285);ctx.font='14px Segoe UI';ctx.fillStyle='#888';ctx.fillText('('+games.length+' game'+(games.length>1?'s':'')+')',cx,310);}else{ctx.fillStyle='#555';ctx.font='18px Segoe UI';ctx.fillText('No old games yet',cx,285);}ctx.fillStyle='#555';ctx.font='13px Segoe UI';ctx.fillText('Capybara Snake — collect oranges, avoid danger',cx,canvas.height-20);msgEl.textContent='Press 1 for New Game, 2 for Old Game';}

function drawNamingScreen(){ctx.fillStyle='#0a0a1a';ctx.fillRect(0,0,canvas.width,canvas.height);var cx=canvas.width/2;ctx.fillStyle='#00ff88';ctx.font='bold 26px Segoe UI';ctx.textAlign='center';ctx.fillText('Name Your Game',cx,100);ctx.fillStyle='#16213e';ctx.fillRect(cx-140,140,280,40);ctx.strokeStyle='#00ff88';ctx.lineWidth=2;ctx.strokeRect(cx-140,140,280,40);ctx.fillStyle='#eee';ctx.font='20px Segoe UI';ctx.fillText(nameInput+(Math.floor(Date.now()/500)%2===0?'|':''),cx,167);ctx.fillStyle='#888';ctx.font='14px Segoe UI';ctx.fillText('Type a name and press Enter',cx,220);ctx.fillText('Press ESC to cancel',cx,245);msgEl.textContent='Type a name for your game';}

function drawRenameScreen(){ctx.fillStyle='#0a0a1a';ctx.fillRect(0,0,canvas.width,canvas.height);var cx=canvas.width/2;var games=getAllGames();var oldName=renamingGameIdx<games.length?games[renamingGameIdx].name:'';ctx.fillStyle='#ffd700';ctx.font='bold 26px Segoe UI';ctx.textAlign='center';ctx.fillText('Rename Game',cx,80);ctx.fillStyle='#888';ctx.font='14px Segoe UI';ctx.fillText('Current: '+oldName,cx,115);ctx.fillStyle='#16213e';ctx.fillRect(cx-140,140,280,40);ctx.strokeStyle='#ffd700';ctx.lineWidth=2;ctx.strokeRect(cx-140,140,280,40);ctx.fillStyle='#eee';ctx.font='20px Segoe UI';ctx.fillText(nameInput+(Math.floor(Date.now()/500)%2===0?'|':''),cx,167);ctx.fillStyle='#888';ctx.font='14px Segoe UI';ctx.fillText('Type new name and press Enter',cx,220);ctx.fillText('Press ESC to cancel',cx,245);msgEl.textContent='Rename your game';}

function drawGameSelect(){var games=getAllGames();ctx.fillStyle='rgba(0,0,0,0.9)';ctx.fillRect(0,0,canvas.width,canvas.height);ctx.textAlign='center';ctx.fillStyle='#ffd700';ctx.font='bold 22px Segoe UI';ctx.fillText('Select a Game',canvas.width/2,40);if(games.length===0){ctx.fillStyle='#888';ctx.font='16px Segoe UI';ctx.fillText('No games yet',canvas.width/2,canvas.height/2);}else{games.forEach(function(g,i){if(i>=9)return;var y=75+i*40;var date=new Date(g.created);var ds=date.toLocaleDateString();var sc=g.saves.length;var bs=sc>0?Math.max.apply(null,g.saves.map(function(s){return s.score;})):0;ctx.fillStyle='#eee';ctx.font='15px Segoe UI';ctx.fillText('['+(i+1)+'] '+g.name+' | Saves: '+sc+' | Best: '+bs+' | '+ds,canvas.width/2,y);});}ctx.fillStyle='#666';ctx.font='13px Segoe UI';if(gameDeleteMode){ctx.fillStyle='#ff4757';ctx.fillText('DELETE — Press number to delete | ESC to cancel',canvas.width/2,canvas.height-20);msgEl.textContent='Delete mode';}else{ctx.fillText('Number=select | R+num=rename | X=delete | ESC=back',canvas.width/2,canvas.height-20);msgEl.textContent='Pick a game';}}

document.addEventListener('keydown',function menuHandler(e){
  if(!menuActive)return;
  if(namingActive){if(e.key==='Escape'){namingActive=false;nameInput='';drawMenu();return;}if(e.key==='Enter'){var name=nameInput.trim()||'Game '+(getAllGames().length+1);namingActive=false;nameInput='';createNewGame(name);return;}if(e.key==='Backspace'){e.preventDefault();nameInput=nameInput.slice(0,-1);drawNamingScreen();return;}if(e.key.length===1&&nameInput.length<20){nameInput+=e.key;drawNamingScreen();}return;}
  if(renamingGameIdx>=0){if(e.key==='Escape'){renamingGameIdx=-1;nameInput='';drawGameSelect();return;}if(e.key==='Enter'){var games=getAllGames();if(renamingGameIdx<games.length&&nameInput.trim()){games[renamingGameIdx].name=nameInput.trim();saveAllGames(games);}renamingGameIdx=-1;nameInput='';drawGameSelect();return;}if(e.key==='Backspace'){e.preventDefault();nameInput=nameInput.slice(0,-1);drawRenameScreen();return;}if(e.key.length===1&&nameInput.length<20){nameInput+=e.key;drawRenameScreen();}return;}
  if(gameSelectActive){if(e.key==='Escape'){if(gameDeleteMode){gameDeleteMode=false;drawGameSelect();}else{gameSelectActive=false;drawMenu();}return;}if((e.key==='x'||e.key==='X')&&!gameDeleteMode){gameDeleteMode=true;drawGameSelect();return;}if(gameDeleteMode){var slot=parseInt(e.key)-1;var games2=getAllGames();if(slot>=0&&slot<games2.length){games2.splice(slot,1);saveAllGames(games2);gameDeleteMode=false;if(games2.length===0){gameSelectActive=false;drawMenu();}else drawGameSelect();}return;}if(e.key==='r'||e.key==='R'){msgEl.textContent='Press number of game to rename...';var rh=function(e2){document.removeEventListener('keydown',rh,true);var sl=parseInt(e2.key)-1;var gms=getAllGames();if(sl>=0&&sl<gms.length){renamingGameIdx=sl;nameInput=gms[sl].name;drawRenameScreen();}else drawGameSelect();e2.stopPropagation();e2.preventDefault();};document.addEventListener('keydown',rh,true);return;}var slot2=parseInt(e.key)-1;var games3=getAllGames();if(slot2>=0&&slot2<games3.length){gameSelectActive=false;menuActive=false;currentGameId=games3[slot2].id;creativeMode=(games3[slot2].name==='CapyBopyCIG');if(games3[slot2].saves.length>0){saveMenuOpen=true;deleteMode2=false;showSaveMenu();}else{init();restartTimer();}}return;}
  if(e.key==='1'){namingActive=true;nameInput='';drawNamingScreen();}
  else if(e.key==='2'){var games4=getAllGames();if(games4.length>0){gameSelectActive=true;gameDeleteMode=false;drawGameSelect();}}
});

drawMenu();
